  1→import type {
  2→	ProjectContributor as ProjectContributorBase,
  3→	ProjectDetailData,
  4→	ProjectError as ProjectErrorBase,
  5→	ProjectFeatureUsage,
  6→	ProjectInvestment,
  7→	ProjectTrendDataPoint as ProjectTrendDataPointBase,
  8→} from "@rudel/api-routes";
  9→import {
 10→	buildDateFilter,
 11→	escapeString,
 12→	queryClickhouse,
 13→} from "../clickhouse.js";
 14→
 15→export interface KnowledgeSilo {
 16→	project_path: string;
 17→	project_name?: string;
 18→	repository_name?: string;
 19→	sole_user: string;
 20→	sessions: number;
 21→	risk_level: "high" | "medium" | "low";
 22→}
 23→
 24→export interface ProjectActivity {
 25→	date: string;
 26→	project_path: string;
 27→	sessions: number;
 28→	unique_users: number;
 29→}
 30→
 31→export interface ProjectSummary {
 32→	total_projects: number;
 33→	projects_with_silos: number;
 34→	avg_users_per_project: number;
 35→	most_active_project: string;
 36→	most_active_sessions: number;
 37→}
 38→
 39→export type ProjectDetails = ProjectDetailData;
 40→
 41→export interface ProjectContributor extends ProjectContributorBase {
 42→	username?: string;
 43→	first_session: string;
 44→	last_session: string;
 45→}
 46→
 47→export interface ProjectError extends ProjectErrorBase {
 48→	first_seen: string;
 49→}
 50→
 51→export interface ProjectTrendDataPoint extends ProjectTrendDataPointBase {
 52→	project_name?: string;
 53→}
 54→
 55→/**
 56→ * Extract project name from path (last segment)
 57→ */
 58→function extractProjectName(projectPath: string): string {
 59→	if (!projectPath) return "";
 60→	const segments = projectPath.replace(/\\/g, "/").split("/").filter(Boolean);
 61→	return segments[segments.length - 1] || projectPath;
 62→}
 63→
 64→/**
 65→ * Extract repository name from path
 66→ */
 67→function extractRepositoryName(projectPath: string): string {
 68→	return extractProjectName(projectPath);
 69→}
 70→
 71→/**
 72→ * Get AI investment by project - where is time being spent?
 73→ */
 74→export async function getProjectInvestment(
 75→	orgId: string,
 76→	params: {
 77→		days?: number;
 78→		limit?: number;
 79→		offset?: number;
 80→		project_path?: string;
 81→		project_paths?: string[];
 82→	} = {},
 83→): Promise<ProjectInvestment[]> {
 84→	const {
 85→		days = 30,
 86→		limit = 20,
 87→		offset = 0,
 88→		project_path,
 89→		project_paths,
 90→	} = params;
 91→	const org = escapeString(orgId);
 92→	const d = Number(days);
 93→	const lim = Number(limit);
 94→	const off = Number(offset);
 95→
 96→	let projectFilter = "";
 97→	if (project_path) {
 98→		projectFilter = `AND project_path = '${escapeString(project_path)}'`;
 99→	} else if (project_paths && project_paths.length > 0) {
100→		const escaped = project_paths.map((p) => `'${escapeString(p)}'`).join(", ");
101→		projectFilter = `AND project_path IN (${escaped})`;
102→	}
103→
104→	const query = `
105→    WITH current_period AS (
106→      SELECT
107→        if(git_remote != '', git_remote, repository) as project_key,
108→        any(git_remote) as git_remote,
109→        any(repository) as repository,
110→        any(project_path) as project_path,
111→        COUNT(*) as sessions,
112→        COUNT(DISTINCT user_id) as unique_users,
113→        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
114→        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
115→        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
116→        round(SUM(actual_duration_min), 2) as total_duration_min,
117→        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
118→        round(AVG(success_score), 2) as success_rate
119→      FROM rudel.session_analytics
120→      WHERE ${buildDateFilter(d)}
121→        AND organization_id = '${org}'
122→        AND (git_remote != '' OR repository != '')
123→        ${projectFilter}
124→      GROUP BY project_key
125→    ),
126→    previous_period AS (
127→      SELECT
128→        if(git_remote != '', git_remote, repository) as project_key,
129→        round(AVG(success_score), 2) as prev_success_rate
130→      FROM rudel.session_analytics
131→      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
132→        AND session_date < now64(3) - INTERVAL ${d} DAY
133→        AND organization_id = '${org}'
134→        AND (git_remote != '' OR repository != '')
135→        ${projectFilter}
136→      GROUP BY project_key
137→    )
138→    SELECT
139→      c.repository,
140→      c.git_remote,
141→      c.project_path,
142→      c.sessions,
143→      c.unique_users,
144→      c.total_tokens,
145→      c.input_tokens_sum as input_tokens,
146→      c.output_tokens_sum as output_tokens,
147→      c.total_duration_min,
148→      c.avg_session_duration_min,
149→      c.success_rate,
150→      round((c.output_tokens_sum / 1000000.0) * 15.0 + (c.input_tokens_sum / 1000000.0) * 3.0, 4) as cost,
151→      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend
152→    FROM current_period c
153→    LEFT JOIN previous_period p ON c.project_key = p.project_key
154→    ORDER BY c.total_duration_min DESC
155→    LIMIT ${lim}
156→    OFFSET ${off}
157→  `;
158→
159→	const results = await queryClickhouse<
160→		ProjectInvestment & { git_remote?: string }
161→	>(query);
162→
163→	return results.map((project) => ({
164→		...project,
165→		repository: project.repository || null,
166→		git_remote: project.git_remote || undefined,
167→	}));
168→}
169→
170→/**
171→ * Get knowledge silos - projects with only one developer
172→ */
173→export async function getKnowledgeSilos(
174→	orgId: string,
175→	params: { days?: number; min_sessions?: number } = {},
176→): Promise<KnowledgeSilo[]> {
177→	const { days = 30, min_sessions = 5 } = params;
178→	const org = escapeString(orgId);
179→	const d = Number(days);
180→	const minSess = Number(min_sessions);
181→
182→	const query = `
183→    SELECT
184→      project_path,
185→      any(user_id) as sole_user,
186→      COUNT(*) as sessions,
187→      CASE
188→        WHEN COUNT(*) >= 20 THEN 'high'
189→        WHEN COUNT(*) >= 10 THEN 'medium'
190→        ELSE 'low'
191→      END as risk_level
192→    FROM rudel.session_analytics
193→    WHERE ${buildDateFilter(d)}
194→      AND organization_id = '${org}'
195→      AND project_path != ''
196→    GROUP BY project_path
197→    HAVING COUNT(DISTINCT user_id) = 1
198→      AND COUNT(*) >= ${minSess}
199→    ORDER BY sessions DESC
200→  `;
201→
202→	const results = await queryClickhouse<KnowledgeSilo>(query);
203→
204→	return results.map((silo) => ({
205→		...silo,
206→		project_name: extractProjectName(silo.project_path),
207→		repository_name: extractRepositoryName(silo.project_path),
208→	}));
209→}
210→
211→/**
212→ * Get project activity trend over time
213→ */
214→export async function getProjectActivity(
215→	orgId: string,
216→	projectPath: string,
217→	params: { days?: number; granularity?: "day" | "week" | "month" } = {},
218→): Promise<ProjectActivity[]> {
219→	const { days = 30, granularity = "day" } = params;
220→	const org = escapeString(orgId);
221→	const pp = escapeString(projectPath);
222→	const d = Number(days);
223→
224→	let dateGrouping = "toDate(session_date)";
225→	if (granularity === "week") {
226→		dateGrouping = "toMonday(session_date)";
227→	} else if (granularity === "month") {
228→		dateGrouping = "toStartOfMonth(session_date)";
229→	}
230→
231→	const query = `
232→    WITH project_key AS (
233→      SELECT if(git_remote != '', git_remote, repository) as pk, any(project_path) as project_path
234→      FROM rudel.session_analytics
235→      WHERE project_path = '${pp}'
236→        AND (git_remote != '' OR repository != '')
237→        AND organization_id = '${org}'
238→      LIMIT 1
239→    )
240→    SELECT
241→      toString(${dateGrouping}) as date,
242→      pk.project_path,
243→      COUNT(*) as sessions,
244→      COUNT(DISTINCT s.user_id) as unique_users
245→    FROM project_key pk
246→    INNER JOIN rudel.session_analytics s ON if(s.git_remote != '', s.git_remote, s.repository) = pk.pk
247→    WHERE s.${buildDateFilter(d)}
248→      AND s.organization_id = '${org}'
249→    GROUP BY ${dateGrouping}, pk.project_path
250→    ORDER BY date ASC
251→  `;
252→
253→	return queryClickhouse<ProjectActivity>(query);
254→}
255→
256→/**
257→ * Get project summary statistics
258→ */
259→export async function getProjectSummary(
260→	orgId: string,
261→	days = 30,
262→): Promise<ProjectSummary> {
263→	const org = escapeString(orgId);
264→	const d = Number(days);
265→
266→	const query = `
267→    WITH project_stats AS (
268→      SELECT
269→        project_path,
270→        COUNT(*) as sessions,
271→        COUNT(DISTINCT user_id) as users
272→      FROM rudel.session_analytics
273→      WHERE ${buildDateFilter(d)}
274→        AND organization_id = '${org}'
275→        AND project_path != ''
276→      GROUP BY project_path
277→    )
278→    SELECT
279→      COUNT(*) as total_projects,
280→      countIf(users = 1 AND sessions >= 5) as projects_with_silos,
281→      round(AVG(users), 2) as avg_users_per_project,
282→      argMax(project_path, sessions) as most_active_project,
283→      max(sessions) as most_active_sessions
284→    FROM project_stats
285→  `;
286→
287→	const result = await queryClickhouse<ProjectSummary>(query);
288→	return (
289→		result[0] || {
290→			total_projects: 0,
291→			projects_with_silos: 0,
292→			avg_users_per_project: 0,
293→			most_active_project: "",
294→			most_active_sessions: 0,
295→		}
296→	);
297→}
298→
299→/**
300→ * Get detailed metrics for a specific project
301→ */
302→export async function getProjectDetails(
303→	orgId: string,
304→	projectPath: string,
305→	days = 30,
306→): Promise<ProjectDetails | null> {
307→	const org = escapeString(orgId);
308→	const pp = escapeString(projectPath);
309→	const d = Number(days);
310→
311→	const query = `
312→    WITH project_key AS (
313→      SELECT if(git_remote != '', git_remote, repository) as pk
314→      FROM rudel.session_analytics
315→      WHERE project_path = '${pp}'
316→        AND (git_remote != '' OR repository != '')
317→        AND organization_id = '${org}'
318→      LIMIT 1
319→    )
320→    SELECT
321→      any(project_path) as project_path,
322→      COUNT(*) as total_sessions,
323→      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
324→      SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
325→      SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
326→      COUNT(DISTINCT user_id) as contributors_count,
327→      countIf(success_score < 40) as errors_count,
328→      round(AVG(actual_duration_min), 2) as avg_session_duration_min,
329→      round(AVG(success_score), 2) as success_rate,
330→      round(SUM(actual_duration_min), 2) as total_duration_min
331→    FROM rudel.session_analytics
332→    WHERE if(git_remote != '', git_remote, repository) = (SELECT pk FROM project_key)
333→    AND ${buildDateFilter(d)}
334→    AND organization_id = '${org}'
335→  `;
336→
337→	const results = await queryClickhouse<
338→		ProjectDetails & {
339→			input_tokens_sum: number;
340→			output_tokens_sum: number;
341→		}
342→	>(query);
343→
344→	const [row] = results;
345→	if (!row) return null;
346→	const cost =
347→		row.output_tokens_sum * 0.000015 + row.input_tokens_sum * 0.000003;
348→	return {
349→		project_path: row.project_path,
350→		total_sessions: row.total_sessions,
351→		total_tokens: row.total_tokens,
352→		contributors_count: row.contributors_count,
353→		errors_count: row.errors_count,
354→		avg_session_duration_min: row.avg_session_duration_min,
355→		success_rate: row.success_rate,
356→		total_duration_min: row.total_duration_min,
357→		cost: parseFloat(cost.toFixed(4)),
358→	};
359→}
