536→export async function getProjectErrors(
537→	orgId: string,
538→	projectPath: string,
539→	days = 30,
540→): Promise<ProjectError[]> {
541→	const org = escapeString(orgId);
542→	const pp = escapeString(projectPath);
543→	const d = Number(days);
544→
545→	const query = `
546→    WITH project_key AS (
547→      SELECT if(git_remote != '', git_remote, repository) as pk
548→      FROM rudel.session_analytics
549→      WHERE project_path = '${pp}'
550→        AND (git_remote != '' OR repository != '')
551→        AND organization_id = '${org}'
552→      LIMIT 1
553→    ),
554→    error_extracts AS (
555→      SELECT
556→        session_id,
557→        user_id,
558→        session_date,
559→        CASE
560→          WHEN content LIKE '%OperationFailed%' THEN 'OperationFailed'
561→          WHEN content LIKE '%UnknownError%' THEN 'UnknownError'
562→          WHEN content LIKE '%ORPCError%' THEN 'ORPCError'
563→          WHEN content LIKE '%TimeoutError%' THEN 'TimeoutError'
564→          WHEN content LIKE '%TypeError%' THEN 'TypeError'
565→          WHEN content LIKE '%ReferenceError%' THEN 'ReferenceError'
566→          WHEN content LIKE '%Error:%' OR content LIKE '%error:%' THEN 'GenericError'
567→          ELSE NULL
568→        END as error_pattern
569→      FROM rudel.session_analytics
570→      WHERE if(git_remote != '', git_remote, repository) = (SELECT pk FROM project_key)
571→        AND ${buildDateFilter(d)}
572→        AND organization_id = '${org}'
573→        AND (content LIKE '%Error:%' OR content LIKE '%error:%')
574→    )
575→    SELECT
576→      error_pattern,
577→      COUNT(*) as occurrences,
578→      uniq(user_id) as affected_users,
579→      toString(min(session_date)) as first_seen,
580→      toString(max(session_date)) as last_seen
581→    FROM error_extracts
582→    WHERE error_pattern IS NOT NULL
583→    GROUP BY error_pattern
584→    ORDER BY occurrences DESC
585→    LIMIT 20
586→  `;
