		limit = 50,
		offset = 0,
		sort_by = "date",
		sort_order = "desc",
	} = params;

	const org = escapeString(orgId);
	const uid = escapeString(userId);
	const d = Number(days);
	const lim = Number(limit);
	const off = Number(offset);

	let filters = "";
	if (project_path) {
		filters += ` AND project_path = '${escapeString(project_path)}'`;
	}
	if (outcome === "success") {
		filters += ` AND actual_duration_min BETWEEN 5 AND 240`;
	}

	const sortColumn =
		sort_by === "duration"
			? "actual_duration_min"
			: sort_by === "tokens"
				? "total_tokens"
				: "session_date";
	const sortDirection = sort_order === "asc" ? "ASC" : "DESC";

	const query = `
    SELECT
      session_id,
      toString(session_date) as session_date,
      project_path,
      actual_duration_min as duration_min,
      ifNull(input_tokens, 0) as input_tokens,
      ifNull(output_tokens, 0) as output_tokens,
      ifNull(input_tokens, 0) + ifNull(output_tokens, 0) as total_tokens,
      length(subagent_types) > 0 as has_subagents,
      length(skills) > 0 as has_skills,
      length(slash_commands) > 0 as has_slash_commands,
      error_count > 0 as has_errors,
      actual_duration_min BETWEEN 5 AND 240 as likely_success
    FROM rudel.session_analytics
    WHERE user_id = '${uid}'
      AND ${buildDateFilter(d)}
      AND organization_id = '${org}'
      ${filters}
    ORDER BY ${sortColumn} ${sortDirection}
    LIMIT ${lim}
    OFFSET ${off}
  `;

	const results = await queryClickhouse<DeveloperSession>(query);

	return results.map((session) => ({
		...session,
		has_subagents: Boolean(session.has_subagents),
		has_skills: Boolean(session.has_skills),
		has_slash_commands: Boolean(session.has_slash_commands),
